{
  "name": "Chalamandra Quantum Mind",
  "description": "An AI-powered dialectical analysis tool that uses three distinct personas—CHOLA (Thesis), MALANDRA (Antithesis), and FRESA (Synthesis)—to deconstruct problems and generate actionable strategies. Users can input a challenge and receive a multi-faceted analysis, adjusting the strategic depth of the final synthesis."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { InputSection } from './components/InputSection';
import { ResultsSection } from './components/ResultsSection';
import { getFullAnalysis, getSynthesisOnly } from './services/geminiService';
import type { AnalysisResult, EvolutionLevel } from './types';

const App: React.FC = () => {
  const [problem, setProblem] = useState<string>("Our startup has built a great product, but we're struggling to find product-market fit. Should we pivot or double down on the current market segment?");
  const [evolutionLevel, setEvolutionLevel] = useState<EvolutionLevel>('6');
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isSynthesizing, setIsSynthesizing] = useState<boolean>(false);

  const handleAnalyze = useCallback(async () => {
    if (!problem.trim()) return;

    setIsLoading(true);
    setAnalysisResult(null);

    try {
      const result = await getFullAnalysis(problem, evolutionLevel);
      setAnalysisResult(result);
    } catch (error) {
      console.error("Error during full analysis:", error);
      // Here you could set an error state to display to the user
    } finally {
      setIsLoading(false);
    }
  }, [problem, evolutionLevel]);

  const handleLevelChange = useCallback(async (newLevel: EvolutionLevel) => {
    setEvolutionLevel(newLevel);
    if (!analysisResult?.thesis || !analysisResult?.antithesis) {
      return;
    }

    setIsSynthesizing(true);
    try {
      const synthesis = await getSynthesisOnly(
        analysisResult.thesis,
        analysisResult.antithesis,
        newLevel
      );
      setAnalysisResult(prev => prev ? { ...prev, synthesis } : null);
    } catch (error) {
      console.error("Error during synthesis-only:", error);
    } finally {
      setIsSynthesizing(false);
    }
  }, [analysisResult]);

  return (
    <div className="min-h-screen bg-black text-gray-200 font-sans p-4 sm:p-6 lg:p-8">
      <div className="max-w-7xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl sm:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-purple-400 via-pink-500 to-red-500">
            CHALAMANDRA
          </h1>
          <p className="text-gray-400 mt-2 text-lg">Quantum Mind Dialectical Flow Guide</p>
        </header>

        <main>
          <InputSection
            problem={problem}
            setProblem={setProblem}
            evolutionLevel={evolutionLevel}
            onLevelChange={handleLevelChange}
            onAnalyze={handleAnalyze}
            isLoading={isLoading}
          />
          <ResultsSection
            result={analysisResult}
            isLoading={isLoading}
            isSynthesizing={isSynthesizing}
          />
        </main>
      </div>
    </div>
  );
};

export default App;

export type EvolutionLevel = '3' | '6' | '9';

export interface CholaResult {
  coreInsight: string;
  strategicView: string;
  costOfInaction: string;
}

export interface MalandraResult {
  fatalFlaw: string;
  deconstruction: string;
  overlookedRisk: string;
  hardQuestion: string;
}

export interface FresaResult {
  level: EvolutionLevel;
  content: {
    title: string;
    details: string[];
  };
}

export interface AnalysisResult {
  thesis: CholaResult;
  antithesis: MalandraResult;
  synthesis: FresaResult;
}

import type { AnalysisResult, CholaResult, MalandraResult, FresaResult, EvolutionLevel } from '../types';
import { PERSONA_PROMPTS } from '../constants';


// This service simulates the behavior of an on-device Gemini Nano model.
// It uses setTimeout to mimic processing time and returns structured, hardcoded data.

const generateCholaResponse = (problem: string): Promise<CholaResult> => {
  console.log("CHOLA Prompt:", PERSONA_PROMPTS.CHOLA + problem);
  return new Promise(resolve => {
    setTimeout(() => {
      resolve({
        coreInsight: "The challenge isn't product vs. market, but signal vs. noise; you must isolate the one metric that proves undeniable value.",
        strategicView: "Your current user base is a crowded plaza. Instead of shouting to everyone, find the one quiet corner cafe where your most loyal patrons gather. Fortify that space, make it perfect for them, and the aroma will draw others in. Expansion follows loyalty, not the other way around.",
        costOfInaction: "Continuing without a clear signal metric is like driving in fog with no headlights; you'll burn all your fuel without ever knowing if you were even on the right road."
      });
    }, 1000 + Math.random() * 500);
  });
};

const generateMalandraResponse = (thesis: CholaResult): Promise<MalandraResult> => {
    console.log("MALANDRA Prompt:", PERSONA_PROMPTS.MALANDRA + JSON.stringify(thesis));
  return new Promise(resolve => {
    setTimeout(() => {
      resolve({
        fatalFlaw: "You're romanticizing loyalty while ignoring the cold, hard math of acquisition cost and retention rate.",
        deconstruction: "The 'quiet corner cafe' is a nice story, but it's an anecdote, not data. Airbnb didn't win by perfecting one host's experience; they won by creating a scalable system for trust. Your 'signal' is undefined, which means it's vanity. Without benchmarks, you can't distinguish a loyal user from a freeloader.",
        overlookedRisk: "You are at risk of optimizing for a cohort of users who love your product but will never represent a scalable market, leading to a 'zombie' startup: alive, but not growing.",
        hardQuestion: "What is the single, non-vanity metric that, if it doubled, would force your investors to double their investment? Why haven't you been measuring it obsessively?"
      });
    }, 1200 + Math.random() * 500);
  });
};

const generateFresaResponse = (thesis: CholaResult, antithesis: MalandraResult, level: EvolutionLevel): Promise<FresaResult> => {
    console.log("FRESA Prompt:", PERSONA_PROMPTS.FRESA + `\nThesis: ${JSON.stringify(thesis)}\nAntithesis: ${JSON.stringify(antithesis)}\nLevel: ${level}`);
  return new Promise(resolve => {
    setTimeout(() => {
      let content;
      switch (level) {
        case '3':
          content = {
            title: "24-Hour Action Plan: The Signal Hunt",
            details: [
              "1. Define the 'P0 User': Identify the 3-5 users who have used the product most in the last 30 days.",
              "2. Conduct 30-Minute Interviews: Personally call them. Ask 'What would you use if we disappeared tomorrow?' and 'What is the primary benefit you receive?'.",
              "3. Instrument One Core Metric: Based on interviews, pick one action (e.g., 'project created', 'report shared') that correlates with their stated value. Track this religiously.",
            ],
          };
          break;
        case '9':
          content = {
            title: "18-Month Vision: The Gravity Well Model",
            details: [
              "Phase 1 (0-6 Months - The Core): Achieve 'power user density'. Become the undisputed best solution for your P0 user profile. Metric: 80% 3-month retention for this cohort.",
              "Phase 2 (6-12 Months - Adjacency): Identify the 'next-most-likely' user segment. Build one bridge feature that pulls them in without alienating your core. Metric: 25% of new signups from this adjacent segment.",
              "Phase 3 (12-18 Months - Ecosystem): Open APIs and integrations. Transform your product from a tool into a platform where your core users can build their own value. Metric: 100+ active integrations and a 50% increase in user-generated value.",
              "Contingency: If core retention fails to hit 80%, a full-stack pivot to serve the needs of the most engaged adjacent segment is authorized.",
            ],
          };
          break;
        case '6':
        default:
          content = {
            title: "The Wedge-to-Scale Roadmap",
            details: [
              "Phase 1 (Validation, Weeks 1-4): Isolate your Power User Cohort. Goal: Achieve a Net Promoter Score (NPS) of 60+ and a 12-week retention rate of >40% within this specific group. This validates the 'great product' assumption.",
              "Phase 2 (Momentum, Weeks 5-12): Double down on the Power User acquisition channel. Goal: Triple the size of the Power User Cohort. All product development focuses exclusively on serving their primary use case.",
              "Phase 3 (Expansion, Weeks 13-24): Build the 'Bridge Feature'. Goal: Identify the single most-requested feature by the adjacent market segment and build it. Measure adoption of this feature as the primary metric for successful market expansion.",
            ],
          };
          break;
      }
      resolve({ level, content });
    }, 1500 + Math.random() * 500);
  });
};

export const getFullAnalysis = async (problem: string, level: EvolutionLevel): Promise<AnalysisResult> => {
  const thesis = await generateCholaResponse(problem);
  const antithesis = await generateMalandraResponse(thesis);
  const synthesis = await generateFresaResponse(thesis, antithesis, level);

  return { thesis, antithesis, synthesis };
};

export const getSynthesisOnly = async (thesis: CholaResult, antithesis: MalandraResult, level: EvolutionLevel): Promise<FresaResult> => {
  return generateFresaResponse(thesis, antithesis, level);
};

import React from 'react';
