import { GoogleGenAI, Type, Schema } from "@google/genai";
import type { AnalysisResult, CholaResult, MalandraResult, FresaResult, EvolutionLevel } from '../types';
import { PERSONA_PROMPTS } from '../constants';

// Initialize the Gemini AI client
// CRITICAL: We strictly follow the rule to use process.env.API_KEY directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We use 'gemini-3-flash-preview' for a balance of high reasoning capability and speed,
// which is essential for a multi-step dialectical flow.
const MODEL_NAME = 'gemini-3-flash-preview';

/**
 * SCHEMA DEFINITIONS
 * We define strict JSON schemas to ensure the AI responds exactly in the format
 * our TypeScript interfaces expect. This eliminates parsing errors.
 */

const cholaSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    coreInsight: { type: Type.STRING, description: "A razor-sharp 1-sentence insight." },
    strategicView: { type: Type.STRING, description: "Elaboration on patterns using urban/market metaphors." },
    costOfInaction: { type: Type.STRING, description: "What is lost by not acting." },
  },
  required: ["coreInsight", "strategicView", "costOfInaction"],
};

const malandraSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    fatalFlaw: { type: Type.STRING, description: "A piercing 1-liner exposing the weakness." },
    deconstruction: { type: Type.STRING, description: "Specific failure points and criticism." },
    overlookedRisk: { type: Type.STRING, description: "A tangible, measurable risk ignored by the thesis." },
    hardQuestion: { type: Type.STRING, description: "A difficult question forcing defense of assumptions." },
  },
  required: ["fatalFlaw", "deconstruction", "overlookedRisk", "hardQuestion"],
};

const fresaSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "The title of the synthesis strategy." },
    details: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "A list of specific steps or phases for the strategy.",
    },
  },
  required: ["title", "details"],
};

/**
 * GENERATION FUNCTIONS
 */

const generateCholaResponse = async (problem: string): Promise<CholaResult> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [
        { role: 'user', parts: [{ text: PERSONA_PROMPTS.CHOLA + "\n\nPROBLEM: " + problem }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: cholaSchema,
        temperature: 0.7, // Slightly creative for the Visionary
      },
    });

    const text = response.text;
    if (!text) throw new Error("Chola returned empty response");
    return JSON.parse(text) as CholaResult;
  } catch (error) {
    console.error("Chola Error:", error);
    throw error;
  }
};

const generateMalandraResponse = async (thesis: CholaResult, problem: string): Promise<MalandraResult> => {
  try {
    const context = `
      ORIGINAL PROBLEM: ${problem}

      THESIS (CHOLA'S VIEW):
      - Insight: ${thesis.coreInsight}
      - View: ${thesis.strategicView}
      - Cost: ${thesis.costOfInaction}
    `;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [
        { role: 'user', parts: [{ text: PERSONA_PROMPTS.MALANDRA + "\n\nCONTEXT TO CRITIQUE:\n" + context }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: malandraSchema,
        temperature: 0.8, // Higher temperature for critical thinking/edge cases
      },
    });

    const text = response.text;
    if (!text) throw new Error("Malandra returned empty response");
    return JSON.parse(text) as MalandraResult;
  } catch (error) {
    console.error("Malandra Error:", error);
    throw error;
  }
};

const generateFresaResponse = async (
  thesis: CholaResult, 
  antithesis: MalandraResult, 
  level: EvolutionLevel, 
  problem: string
): Promise<FresaResult> => {
  try {
    const context = `
      ORIGINAL PROBLEM: ${problem}

      THESIS (CHOLA): ${JSON.stringify(thesis)}

      ANTITHESIS (MALANDRA): ${JSON.stringify(antithesis)}
    `;

    // Map level to specific instructions for the prompt
    let levelInstruction = "";
    if (level === '3') levelInstruction = "Create a Level 3 (Actionable) plan: Immediate next steps for the next 24 hours.";
    if (level === '6') levelInstruction = "Create a Level 6 (Strategic) plan: A 3-phase roadmap.";
    if (level === '9') levelInstruction = "Create a Level 9 (Quantum) plan: A 12-18 month visionary plan.";

    const fullPrompt = `${PERSONA_PROMPTS.FRESA}\n\n${levelInstruction}\n\nDIALECTICAL CONTEXT:\n${context}`;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [
        { role: 'user', parts: [{ text: fullPrompt }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: fresaSchema,
        temperature: 0.6, // Balanced and precise for Synthesis
      },
    });

    const text = response.text;
    if (!text) throw new Error("Fresa returned empty response");

    const content = JSON.parse(text);

    return {
      level,
      content: {
        title: content.title,
        details: content.details
      }
    };
  } catch (error) {
    console.error("Fresa Error:", error);
    throw error;
  }
};

/**
 * ORCHESTRATORS
 */

export const getFullAnalysis = async (problem: string, level: EvolutionLevel): Promise<AnalysisResult> => {
  // 1. Run Chola (Thesis)
  const thesis = await generateCholaResponse(problem);

  // 2. Run Malandra (Antithesis) - Needs Thesis + Problem
  const antithesis = await generateMalandraResponse(thesis, problem);

  // 3. Run Fresa (Synthesis) - Needs Thesis + Antithesis + Problem + Level
  const synthesis = await generateFresaResponse(thesis, antithesis, level, problem);

  return { thesis, antithesis, synthesis };
};

export const getSynthesisOnly = async (
  thesis: CholaResult, 
  antithesis: MalandraResult, 
  level: EvolutionLevel
): Promise<FresaResult> => {
  // When re-running synthesis (changing levels), we might lose the original problem string 
  // if not passed. For this architecture, we will infer the problem context from the 
  // thesis/antithesis content which is sufficient for synthesis.
  const inferredContext = "Synthesize based on the provided Thesis and Antithesis.";
  return generateFresaResponse(thesis, antithesis, level, inferredContext);
};

export type EvolutionLevel = '3' | '6' | '9';

export interface CholaResult {
  coreInsight: string;
  strategicView: string;
  costOfInaction: string;
}

export interface MalandraResult {
  fatalFlaw: string;
  deconstruction: string;
  overlookedRisk: string;
  hardQuestion: string;
}

// Internal content structure for Fresa
interface FresaContent {
  title: string;
  details: string[];
}

export interface FresaResult {
  level: EvolutionLevel;
  content: FresaContent;
}

export interface AnalysisResult {
  thesis: CholaResult;
  antithesis: MalandraResult;
  synthesis: FresaResult;
}

{
  "name": "Chalamandra Quantum Mind",
  "description": "An AI-powered dialectical analysis tool. Features: Search Grounding, Thinking Models, Flash-Lite speed, and Neural TTS.",
