import { GoogleGenAI, Type, Schema, Modality } from "@google/genai";
import type { AnalysisResult, CholaResult, MalandraResult, FresaResult, EvolutionLevel, GroundingChunk } from '../types';
import { PERSONA_PROMPTS } from '../constants';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// MODEL CONSTANTS
const MODEL_REALITY = 'gemini-3-flash-preview';      // Chola (Grounding)
const MODEL_CRITIC = 'gemini-3-flash-preview';       // Malandra (Logic)
const MODEL_SPEED = 'gemini-2.5-flash-lite-preview-02-05'; // Fresa Level 3 (Fast) - Using specific version or alias
const MODEL_BALANCE = 'gemini-3-flash-preview';      // Fresa Level 6 (Standard)
const MODEL_QUANTUM = 'gemini-3-pro-preview';        // Fresa Level 9 (Thinking)
const MODEL_VOICE = 'gemini-2.5-flash-preview-tts';  // Audio Output

/**
 * SCHEMA DEFINITIONS
 */
const cholaSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    coreInsight: { type: Type.STRING, description: "A razor-sharp 1-sentence insight." },
    strategicView: { type: Type.STRING, description: "Elaboration on patterns using urban/market metaphors." },
    costOfInaction: { type: Type.STRING, description: "What is lost by not acting." },
  },
  required: ["coreInsight", "strategicView", "costOfInaction"],
};

const malandraSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    fatalFlaw: { type: Type.STRING, description: "A piercing 1-liner exposing the weakness." },
    deconstruction: { type: Type.STRING, description: "Specific failure points and criticism." },
    overlookedRisk: { type: Type.STRING, description: "A tangible, measurable risk ignored by the thesis." },
    hardQuestion: { type: Type.STRING, description: "A difficult question forcing defense of assumptions." },
  },
  required: ["fatalFlaw", "deconstruction", "overlookedRisk", "hardQuestion"],
};

const fresaSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "The title of the synthesis strategy." },
    details: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "A list of specific steps or phases for the strategy.",
    },
  },
  required: ["title", "details"],
};

/**
 * GENERATION FUNCTIONS
 */

// 1. CHOLA: The Thesis (Grounded with Search)
const generateCholaResponse = async (problem: string): Promise<CholaResult> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_REALITY,
      contents: [
        { role: 'user', parts: [{ text: PERSONA_PROMPTS.CHOLA + "\n\nPROBLEM: " + problem }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: cholaSchema,
        temperature: 0.7,
        tools: [{ googleSearch: {} }], // ENABLE SEARCH GROUNDING
      },
    });

    const text = response.text;
    if (!text) throw new Error("Chola returned empty response");

    const result = JSON.parse(text) as CholaResult;

    // Extract Grounding Metadata
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] | undefined;
    if (chunks) {
      result.groundingChunks = chunks;
    }

    return result;
  } catch (error) {
    console.error("Chola Error:", error);
    throw error;
  }
};

// 2. MALANDRA: The Antithesis (Pure Logic)
const generateMalandraResponse = async (thesis: CholaResult, problem: string): Promise<MalandraResult> => {
  try {
    const context = `
      ORIGINAL PROBLEM: ${problem}
      THESIS (CHOLA'S VIEW):
      - Insight: ${thesis.coreInsight}
      - View: ${thesis.strategicView}
      - Cost: ${thesis.costOfInaction}
    `;

    const response = await ai.models.generateContent({
      model: MODEL_CRITIC,
      contents: [
        { role: 'user', parts: [{ text: PERSONA_PROMPTS.MALANDRA + "\n\nCONTEXT TO CRITIQUE:\n" + context }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: malandraSchema,
        temperature: 0.8,
      },
    });

    const text = response.text;
    if (!text) throw new Error("Malandra returned empty response");
    return JSON.parse(text) as MalandraResult;
  } catch (error) {
    console.error("Malandra Error:", error);
    throw error;
  }
};

// 3. FRESA: The Synthesis (Adaptive Models)
const generateFresaResponse = async (
  thesis: CholaResult, 
  antithesis: MalandraResult, 
  level: EvolutionLevel, 
  problem: string
): Promise<FresaResult> => {
  try {
    const context = `
      ORIGINAL PROBLEM: ${problem}
      THESIS (CHOLA): ${JSON.stringify(thesis)}
      ANTITHESIS (MALANDRA): ${JSON.stringify(antithesis)}
    `;

    let levelInstruction = "";
    let selectedModel = MODEL_BALANCE;
    let config: any = {
      responseMimeType: "application/json",
      responseSchema: fresaSchema,
    };

    // ADAPTIVE LOGIC
    if (level === '3') {
      // FAST RESPONSE
      selectedModel = 'gemini-2.5-flash-lite-preview-02-05'; // Explicitly use Lite
      levelInstruction = "Create a Level 3 (Actionable) plan: Immediate next steps for the next 24 hours. Be concise.";
      config.temperature = 0.5;
    } else if (level === '6') {
      // BALANCED RESPONSE
      selectedModel = MODEL_BALANCE;
      levelInstruction = "Create a Level 6 (Strategic) plan: A 3-phase roadmap.";
      config.temperature = 0.6;
    } else if (level === '9') {
      // DEEP THINKING RESPONSE
      selectedModel = MODEL_QUANTUM;
      levelInstruction = "Create a Level 9 (Quantum) plan: A 12-18 month visionary plan with deep contingency analysis.";

      // Thinking Config (Gemini 3 Pro)
      // Note: When using thinkingConfig, we do NOT set maxOutputTokens to avoid cutting off the thought process.
      config = {
        responseMimeType: "application/json",
        responseSchema: fresaSchema,
        thinkingConfig: { thinkingBudget: 32768 }, // MAX THINKING BUDGET
      };
    }

    const fullPrompt = `${PERSONA_PROMPTS.FRESA}\n\n${levelInstruction}\n\nDIALECTICAL CONTEXT:\n${context}`;

    const response = await ai.models.generateContent({
      model: selectedModel,
      contents: [
        { role: 'user', parts: [{ text: fullPrompt }] }
      ],
      config: config,
    });

    const text = response.text;
    if (!text) throw new Error("Fresa returned empty response");

    const content = JSON.parse(text);

    return {
      level,
      content: {
        title: content.title,
        details: content.details
      }
    };
  } catch (error) {
    console.error("Fresa Error:", error);
    throw error;
  }
};

// 4. AUDIO GENERATION (TTS)
export const generateSpeech = async (textToSpeak: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_VOICE,
      contents: [{ parts: [{ text: textToSpeak }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' }, // 'Kore' fits the Fresa/Elegant persona
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data received");

    return base64Audio;
  } catch (error) {
    console.error("TTS Error:", error);
    throw error;
  }
};

/**
 * ORCHESTRATORS
 */

export const getFullAnalysis = async (problem: string, level: EvolutionLevel): Promise<AnalysisResult> => {
  const thesis = await generateCholaResponse(problem);
  const antithesis = await generateMalandraResponse(thesis, problem);
  const synthesis = await generateFresaResponse(thesis, antithesis, level, problem);
  return { thesis, antithesis, synthesis };
};

export const getSynthesisOnly = async (
  thesis: CholaResult, 
  antithesis: MalandraResult, 
  level: EvolutionLevel
): Promise<FresaResult> => {
  const inferredContext = "Synthesize based on the provided Thesis and Antithesis.";
  return generateFresaResponse(thesis, antithesis, level, inferredContext);
};

