// SINGLETON AUDIO MANAGER (Chalamandra Audio Engine)
// Prevents "AudioContext limit reached" errors by reusing the context.
class AudioEngine {
  private static instance: AudioEngine;
  private context: AudioContext | null = null;
  private currentSource: AudioBufferSourceNode | null = null;

  private constructor() {}

  public static getInstance(): AudioEngine {
    if (!AudioEngine.instance) {
      AudioEngine.instance = new AudioEngine();
    }
    return AudioEngine.instance;
  }

  private getContext(): AudioContext {
    if (!this.context) {
      this.context = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (this.context.state === 'suspended') {
      this.context.resume();
    }
    return this.context;
  }

  public stop() {
    if (this.currentSource) {
      try {
        this.currentSource.stop();
      } catch (e) {
        // Ignore errors if already stopped
      }
      this.currentSource = null;
    }
  }

  public async play(base64String: string, onEnded: () => void) {
    this.stop(); // Stop any currently playing audio

    const ctx = this.getContext();

    try {
      // Decode Base64
      const binaryString = atob(base64String);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
          bytes[i] = binaryString.charCodeAt(i);
      }

      const audioBuffer = await ctx.decodeAudioData(bytes.buffer);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);

      source.onended = () => {
        this.currentSource = null;
        onEnded();
      };

      this.currentSource = source;
      source.start(0);
    } catch (e) {
      console.error("Audio Engine Error:", e);
      onEnded(); // Ensure UI resets even if error
    }
  }
}

